package ru.memearena.tournament.domain; import jakarta.persistence.*; import java.time.*; import java.util.*; @Entity @Table(name="tournament") public class Tournament{ @Id public UUID id; @Column(name="tournament_date") public LocalDate tournamentDate; @Enumerated(EnumType.STRING) public TournamentStatus status; @Column(name="current_round") public int currentRound; @Column(name="winner_meme_id") public UUID winnerMemeId; @Column(name="starts_at") public Instant startsAt; @Column(name="completed_at") public Instant completedAt; @Column(name="created_at") public Instant createdAt; @Column(name="updated_at") public Instant updatedAt; protected Tournament(){} public Tournament(UUID id,LocalDate d,Instant now){this.id=id;this.tournamentDate=d;this.status=TournamentStatus.ACTIVE;this.currentRound=1;this.startsAt=now;this.createdAt=now;this.updatedAt=now;} public UUID getId(){return id;} public LocalDate getTournamentDate(){return tournamentDate;} public TournamentStatus getStatus(){return status;} public int getCurrentRound(){return currentRound;} public UUID getWinnerMemeId(){return winnerMemeId;} public Instant getStartsAt(){return startsAt;} public Instant getCompletedAt(){return completedAt;} }
